read.filter:
{
      $or: [
        { createdBy: teacherId },
        { teacherId: teacherId },
        { teacherOfRecord: teacherId },
        { members: { $elemMatch: { roleInClass: "TEACHER", userId: teacherId } } }
      ]
    }

read.pipeline:
[
      { $match: buildClassroomMatch(schoolId) },
      { $unwind: "$members" },
      { $match: { "members.roleInClass": "STUDENT" } },
      {
        $group: {
          _id: "$members.userId",
          classroomIds: { $addToSet: "$id" }
        }
      },
      {
        $project: {
          _id: 0,
          userId: "$_id",
          classroomIds: 1,
          classroomCount: { $size: "$classroomIds" }
        }
      },
      { $sort: { userId: 1 } }
    ]

